kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelSoftmaxCustom {
public:
    __aicore__ inline KernelSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t D)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        D_ = D;
        B_ = totalLen_ / D_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Distribute rows evenly among blocks
        uint32_t rowsPerBlock = (B_ + blockNum - 1) / blockNum;
        uint32_t rowStart = blockIdx * rowsPerBlock;
        uint32_t rowEnd = (blockIdx + 1) * rowsPerBlock;
        if (rowEnd > B_) rowEnd = B_;

        for (uint32_t row = rowStart; row < rowEnd; row++) {
            ProcessRow(row);
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t row)
    {
        uint32_t base = row * D_;

        // --- Phase 1: compute max and sum (online-softmax) ---
        float rowMax = -1e38f;
        float rowSum = 0.0f;

        for (uint32_t offset = 0; offset < D_; offset += tileLen_) {
            uint32_t curLen = (offset + tileLen_ <= D_) ? tileLen_ : (D_ - offset);
            // Load tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[base + offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();

            // Compute local max
            float localMax;
            AscendC::ReduceMax(localMax, xLocal, curLen);

            // Update rowMax and rowSum with scaling if needed
            if (localMax > rowMax) {
                // Multiply previous sum by exp(oldMax - newMax)
                rowSum *= AscendC::Exp<float>(rowMax - localMax);
                rowMax = localMax;
            }

            // Compute contribution of current tile: sum(exp(x - rowMax))
            AscendC::LocalTensor<float> expLocal = tmpQueue_.AllocTensor<float>();
            AscendC::Sub(expLocal, xLocal, rowMax, curLen);
            AscendC::Exp(expLocal, expLocal, curLen);

            float tileSum;
            AscendC::ReduceAdd(tileSum, expLocal, curLen);
            rowSum += tileSum;

            tmpQueue_.FreeTensor(expLocal);
            inQueueX_.FreeTensor(xLocal);
        }

        // --- Phase 2: compute normalized output ---
        float invSum = 1.0f / rowSum;
        for (uint32_t offset = 0; offset < D_; offset += tileLen_) {
            uint32_t curLen = (offset + tileLen_ <= D_) ? tileLen_ : (D_ - offset);

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[base + offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();

            // y = exp(x - rowMax) * invSum
            AscendC::Sub(tmpLocal, xLocal, rowMax, curLen);
            AscendC::Exp(tmpLocal, tmpLocal, curLen);
            AscendC::Mul(yLocal, tmpLocal, invSum, curLen);

            tmpQueue_.FreeTensor(tmpLocal);
            outQueueY_.EnQue<float>(yLocal);
            inQueueX_.FreeTensor(xLocal);

            yLocal = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[base + offset], yLocal, curLen);
            outQueueY_.FreeTensor(yLocal);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t D_ {0};
    uint32_t B_ {0};
};

extern "C" __global__ __aicore__ void softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.D);
    op.Process();
}
